import{_ as e}from"./chunks/home-dashboard.BjFBEKEr.js";import{_ as o,o as a,c as r,ag as n}from"./chunks/framework.C9sp7nFj.js";const y=JSON.parse('{"title":"Getting started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1776880543000}'),s={name:"guide/getting-started.md"};function i(l,t,d,h,u,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h1><p>Welcome to Fateh HR. This guide gets you from &quot;just installed the app&quot; to &quot;checked in and ready to work&quot; in under three minutes.</p><h2 id="what-fateh-hr-does" tabindex="-1">What Fateh HR does <a class="header-anchor" href="#what-fateh-hr-does" aria-label="Permalink to &quot;What Fateh HR does&quot;">​</a></h2><p>Fateh HR is the mobile app for your HR life. You use it to:</p><ul><li><strong>Check in / check out</strong> of your workday with location + optional selfie</li><li><strong>Apply for leave</strong> and see your balance</li><li><strong>File expense claims</strong> with receipt photos</li><li><strong>View and download payslips</strong></li><li><strong>See your attendance calendar</strong> for any month</li></ul><p>It works on any Android phone, and also runs as a web app in your browser. Most importantly — <strong>it works offline</strong>. If you&#39;re in a warehouse with no signal or out on a delivery route, just use the app as normal. Your check-ins and requests queue up locally and sync the moment you&#39;re back online.</p><h2 id="before-your-first-login" tabindex="-1">Before your first login <a class="header-anchor" href="#before-your-first-login" aria-label="Permalink to &quot;Before your first login&quot;">​</a></h2><p>You&#39;ll need:</p><ul><li>Your <strong>work email</strong> (the one your HR team registered for you)</li><li>Your <strong>password</strong> (sent to you by HR — reset from the Desk if you&#39;ve forgotten it)</li><li>The Fateh HR <strong>app installed</strong> — see <a href="/guide/install">Install the app</a></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you don&#39;t know your email or password yet, ask your HR team. They can create or reset your account from the Frappe HR desk.</p></div><h2 id="your-first-3-minutes" tabindex="-1">Your first 3 minutes <a class="header-anchor" href="#your-first-3-minutes" aria-label="Permalink to &quot;Your first 3 minutes&quot;">​</a></h2><p>Once the app is installed, here&#39;s the quickest path to a working setup:</p><ol><li><strong>Open Fateh HR</strong></li><li><strong>Log in</strong> with your work email and password → <a href="/guide/login">details</a></li><li><strong>Set a PIN</strong> (4–6 digits) — this is what you&#39;ll use every day instead of the full password → <a href="/guide/login#set-your-pin">details</a></li><li><strong>Enable biometric unlock</strong> when asked — skip typing the PIN by using your fingerprint / face → <a href="/guide/biometric">details</a></li><li>You&#39;re on the home screen. Tap <strong>&quot;Check In&quot;</strong> to start your day.</li></ol><p>From now on, you only need to enter your password again if you log out. Day to day it&#39;s PIN or fingerprint.</p><h2 id="what-each-tab-does" tabindex="-1">What each tab does <a class="header-anchor" href="#what-each-tab-does" aria-label="Permalink to &quot;What each tab does&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tab</th><th>What&#39;s there</th></tr></thead><tbody><tr><td><strong>Home</strong></td><td>Current status (IN / OUT), the check-in button, your last 3 check-ins, latest announcement</td></tr><tr><td><strong>Attendance</strong></td><td>Monthly calendar view — tap any day to see IN / OUT pairs and total hours</td></tr><tr><td><strong>Leave</strong></td><td>Your leave balances, request form, recent applications, and history</td></tr><tr><td><strong>Expense</strong></td><td>Totals (Claimed, Pending, Approved, Paid), new claim button, recent claims</td></tr><tr><td><strong>More</strong></td><td>Profile, payslips, announcements, notifications, sync errors, language, logout</td></tr></tbody></table><figure class="screenshot"><img src="'+e+'" alt="Fateh HR home screen"><figcaption>Home tab — greeting, current check-in state, quick tiles for Leave / Expense / Tasks / Payslips, and the last three check-ins.</figcaption></figure><h3 id="worked-today-card" tabindex="-1">Worked today card <a class="header-anchor" href="#worked-today-card" aria-label="Permalink to &quot;Worked today card&quot;">​</a></h3><p>Just below the Check-in card, a <strong>&quot;Worked today&quot;</strong> chip shows how many hours you&#39;ve clocked today (e.g. <code>8h 12m</code>). It&#39;s the sum of all your completed IN → OUT pairs for the day. While you&#39;re still checked IN it <strong>ticks live</strong> — a small green pulse marks the running state, and the number increments every second.</p><h2 id="when-the-sync-bar-turns-orange" tabindex="-1">When the sync bar turns orange <a class="header-anchor" href="#when-the-sync-bar-turns-orange" aria-label="Permalink to &quot;When the sync bar turns orange&quot;">​</a></h2><p>At the top of most screens you&#39;ll see a thin status bar:</p><ul><li><strong>Synced now</strong> (grey) — everything saved to the server</li><li><strong>5 changes pending · tap to sync</strong> (amber) — you have offline items waiting</li><li><strong>Syncing…</strong> (blue) — actively uploading</li><li><strong>Offline — working locally</strong> (grey) — no network, but everything you do still saves locally</li><li><strong>2 sync errors</strong> (red) — something failed; tap to see why</li></ul><p>If you see the red state, open it and tap <strong>Retry</strong>. It&#39;s almost always a temporary network hiccup.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/guide/install">Install the app</a> if you haven&#39;t yet</li><li><a href="/guide/biometric">Set up biometric unlock</a> for one-tap unlock</li><li><a href="/guide/offline">Learn the offline behaviour</a> — the single most useful thing to know</li><li><a href="/guide/check-in">Check in for the first time</a></li></ul>',25)])])}const f=o(s,[["render",i]]);export{y as __pageData,f as default};
